:root {
    /* ===== CORES PRINCIPAIS (PERSONALIZÁVEIS) ===== */
    --primary-color: #28a745; /* Verde principal */
    --primary-dark: #1e7e34; /* Verde escuro */
    --primary-color-dark: #1e7e34; /* Alias para compatibilidade */
    --primary-light: rgba(40, 167, 69, 0.1); /* Verde claro transparente */
    --primary-hover: rgba(40, 167, 69, 0.8); /* Verde hover */
    --primary-gradient: linear-gradient(135deg, #28a745 0%, #20c997 100%); /* Gradiente principal */

    /* ===== CORES DO SISTEMA ===== */
    --secondary-color: #6c757d;
    --success-color: #28a745;
    --warning-color: #ffc107;
    --danger-color: #dc3545;
    --info-color: #17a2b8;
    --light-color: #f8f9fa;
    --dark-color: #343a40;
    --border-color: #dee2e6;
    --text-primary: #212529;
    --text-secondary: #6c757d;
    --text-muted: #9ca3af;
    --text-light: #ffffff;

    /* ===== CORES DE FUNDO ===== */
    --bg-primary: #ffffff;
    --bg-secondary: #f8f9fa;
    --bg-tertiary: #e9ecef;
    --bg-dark: #212529;
    --bg-gradient: linear-gradient(135deg, var(--bg-secondary) 0%, var(--bg-tertiary) 100%);

    /* ===== ESPAÇAMENTO ===== */
    --spacing-xs: 0.25rem;
    --spacing-sm: 0.5rem;
    --spacing-md: 1rem;
    --spacing-lg: 1.5rem;
    --spacing-xl: 2rem;
    --spacing-2xl: 3rem;
    --spacing-3xl: 4rem;

    /* ===== TIPOGRAFIA ===== */
    --font-family-base: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', 'Oxygen', 'Ubuntu', 'Cantarell', sans-serif;
    --font-family-mono: 'SF Mono', Monaco, 'Inconsolata', 'Roboto Mono', 'Source Code Pro', monospace;

    --font-size-xs: 0.75rem;
    --font-size-sm: 0.875rem;
    --font-size-base: 1rem;
    --font-size-lg: 1.125rem;
    --font-size-xl: 1.25rem;
    --font-size-2xl: 1.5rem;
    --font-size-3xl: 2rem;
    --font-size-4xl: 2.5rem;

    --font-weight-light: 300;
    --font-weight-normal: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;
    --font-weight-black: 900;

    /* Border radius */
    --border-radius: 0.375rem;
    --border-radius-md: 0.5rem;
    --border-radius-lg: 0.75rem;
    --border-radius-xl: 1rem;

    /* ===== SOMBRAS ===== */
    --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
    --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
    --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
    --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1);
    --shadow-2xl: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
    --shadow-inner: inset 0 2px 4px 0 rgba(0, 0, 0, 0.06);
    --shadow-colored: 0 10px 15px -3px rgba(40, 167, 69, 0.1);

    /* ===== TRANSIÇÕES E ANIMAÇÕES ===== */
    --transition: all 0.3s ease;
    --transition-fast: all 0.15s ease;
    --transition-slow: all 0.5s ease;
    --transition-bounce: all 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);

    /* ===== BREAKPOINTS (para referência) ===== */
    --breakpoint-sm: 576px;
    --breakpoint-md: 768px;
    --breakpoint-lg: 992px;
    --breakpoint-xl: 1200px;
    --breakpoint-2xl: 1400px;

    /* ===== Z-INDEX ===== */
    --z-dropdown: 1000;
    --z-sticky: 1020;
    --z-fixed: 1030;
    --z-modal-backdrop: 1040;
    --z-modal: 1050;
    --z-popover: 1060;
    --z-tooltip: 1070;
}

/* Button Styles */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0.75rem 1.5rem;
    font-size: var(--font-size-base);
    font-weight: 500;
    text-decoration: none;
    border: none;
    border-radius: var(--border-radius);
    cursor: pointer;
    transition: var(--transition);
    gap: 0.5rem;
}

.btn-primary {
    background-color: var(--primary-color);
    color: white;
}

.btn-primary:hover {
    background-color: var(--primary-dark);
    color: white;
    text-decoration: none;
}

.btn-secondary {
    background-color: var(--secondary-color);
    color: white;
}

.btn-secondary:hover {
    background-color: #5a6268;
    color: white;
    text-decoration: none;
}

/* Utility Classes */
.text-muted {
    color: var(--text-muted) !important;
}

.text-secondary {
    color: var(--text-secondary) !important;
}

.text-success {
    color: var(--success-color) !important;
}

.text-danger {
    color: var(--danger-color) !important;
}

.text-warning {
    color: var(--warning-color) !important;
}

.text-info {
    color: var(--info-color) !important;
}

/* Integration Status Colors */
.integration-status.connected {
    color: var(--success-color) !important; /* Verde para conectado */
}

.integration-status {
    color: var(--danger-color); /* Vermelho para desconectado (padrão) */
}

/* Container */
.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 var(--spacing-md);
}

/* ===== ELEMENTOS DE MARCA ===== */
.logo {
    color: var(--primary-color);
    font-weight: 700;
    font-size: 1.5rem;
}

.logo-image, .brand-logo {
    max-height: 200px;
    width: auto;
}

.brand-name, .restaurant-brand {
    color: var(--primary-color);
    font-weight: 600;
}

/* ===== ELEMENTOS TEMÁTICOS ===== */
.themed-border {
    border-color: var(--primary-color) !important;
}

.themed-bg {
    background-color: var(--primary-color) !important;
    color: white !important;
}

.themed-bg-light {
    background-color: var(--primary-light) !important;
    color: var(--primary-color) !important;
}

.themed-text {
    color: var(--primary-color) !important;
}

.themed-link {
    color: var(--primary-color);
    text-decoration: none;
    transition: var(--transition);
}

.themed-link:hover {
    color: var(--primary-dark);
    text-decoration: underline;
}

/* ===== BOTÕES TEMÁTICOS ===== */
.btn-success {
    background-color: var(--success-color);
    color: white;
}

.btn-success:hover {
    background-color: var(--primary-dark);
    color: white;
}

.btn-outline-primary {
    border: 1px solid var(--primary-color);
    color: var(--primary-color);
    background: transparent;
}

.btn-outline-primary:hover {
    background-color: var(--primary-color);
    color: white;
}

/* ===== SIDEBAR TEMÁTICA ===== */
.nav-link.active {
    background-color: var(--primary-light) !important;
    color: var(--primary-color) !important;
}

.nav-link.active .nav-icon {
    color: var(--primary-color) !important;
}

/* ===== CARDS E CONTAINERS ===== */
.card-primary {
    border-top: 3px solid var(--primary-color);
}

.card-primary .card-header {
    background-color: var(--primary-light);
    color: var(--primary-color);
}

/* ===== INDICADORES ===== */
.badge-primary {
    background-color: var(--primary-color);
    color: white;
}

.progress-primary .progress-bar {
    background-color: var(--primary-color);
}

/* ===== ALERTS TEMÁTICOS ===== */
.alert-primary {
    background-color: var(--primary-light);
    border-color: var(--primary-color);
    color: var(--primary-color);
}

/* ===== FORMS TEMÁTICOS ===== */
.form-control:focus {
    border-color: var(--primary-color);
    box-shadow: 0 0 0 0.2rem var(--primary-light);
}

.form-check-input:checked {
    background-color: var(--primary-color);
    border-color: var(--primary-color);
}

/* ===== TABLES TEMÁTICAS ===== */
.table-primary th {
    background-color: var(--primary-color);
    color: white;
}

.table-striped tbody tr:nth-of-type(odd) {
    background-color: var(--primary-light);
}

/* ===== ANIMATIONS ===== */
@keyframes pulseTheme {
    0% {
        box-shadow: 0 0 0 0 var(--primary-color);
    }
    70% {
        box-shadow: 0 0 0 10px rgba(var(--primary-color), 0);
    }
    100% {
        box-shadow: 0 0 0 0 rgba(var(--primary-color), 0);
    }
}

.pulse-theme {
    animation: pulseTheme 2s infinite;
}

/* ===== DARK MODE SUPPORT ===== */
@media (prefers-color-scheme: dark) {
    :root {
        --bg-primary: #1a1a1a;
        --bg-secondary: #2d2d2d;
        --bg-tertiary: #404040;
        --text-primary: #ffffff;
        --text-secondary: #cccccc;
        --border-color: #404040;
    }
}

/* ===== RESPONSIVE DESIGN ===== */
@media (max-width: 768px) {
    .container {
        padding: 0 var(--spacing-sm);
    }

    .logo-image, .brand-logo {
        max-height: 32px;
    }

    .btn {
        padding: 0.5rem 1rem;
        font-size: var(--font-size-sm);
    }
}

