            }

            // 3. Verificar localStorage para sessão específica
            const instance = window.SECURE_INSTANCE_MANAGER.getInstance();
            const storedPhone = localStorage.getItem(`customer_phone_${instance.restaurantId}`);
            if (storedPhone) {
